import { toFinite } from 'lodash-es';

import { isNumericalMarker } from './is-numerical-marker.js';
import {
  NumericalMarkerProps,
  TimeMarkerProps,
} from '../types/annotations-marker-props.js';

const serializeNumericalRange = ({ start, end }: NumericalMarkerProps) =>
  [start, end ?? start].join('_');
const serializeTimeRange = ({ start, end }: TimeMarkerProps) =>
  [start.getTime(), end?.getTime() ?? start.getTime()].join('_');

export const serializeMarkerRange = (
  marker: TimeMarkerProps | NumericalMarkerProps,
  trackIndex: number,
) => {
  const markerString = isNumericalMarker(marker)
    ? serializeNumericalRange(marker)
    : serializeTimeRange(marker);
  return `${trackIndex}_${markerString}`;
};

export const deserializeMarkerRange = (
  range: string,
): [number, number, number] => {
  const [trackIndex, from, to] = range.split('_').map(toFinite);

  return [from, to, trackIndex];
};
